CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
INSERT INTO "d1_migrations" VALUES(1,'0000_initial_schema.sql','2026-02-14 14:57:31');
CREATE TABLE deals (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  client_id INTEGER,
  title TEXT NOT NULL,
  amount REAL DEFAULT 0,
  stage TEXT DEFAULT 'lead',
  probability INTEGER DEFAULT 30,
  expected_close_date DATE,
  notes TEXT,
  created_at DATETIME DEFAULT (datetime('now')),
  updated_at DATETIME DEFAULT (datetime('now')), archived INTEGER DEFAULT 0, rdv_date TEXT, rdv_notes TEXT,
  FOREIGN KEY (client_id) REFERENCES clients(id)
);
CREATE TABLE email_categories (
        email_id TEXT PRIMARY KEY,
        category TEXT NOT NULL,
        updated_at DATETIME DEFAULT (datetime('now'))
      );
CREATE TABLE leads (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        source TEXT NOT NULL DEFAULT 'email',
        source_ref TEXT NOT NULL UNIQUE,
        from_name TEXT,
        from_email TEXT,
        subject TEXT,
        snippet TEXT,
        body TEXT,
        stage TEXT NOT NULL DEFAULT 'new',
        priority TEXT DEFAULT 'normal',
        confidence INTEGER DEFAULT 0,
        created_at DATETIME NOT NULL DEFAULT (datetime('now')),
        updated_at DATETIME DEFAULT (datetime('now'))
      );
CREATE TABLE quote_items (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            quote_id INTEGER NOT NULL,
            position INTEGER DEFAULT 0,
            title TEXT NOT NULL,
            description TEXT,
            qty REAL DEFAULT 1,
            unit TEXT DEFAULT 'u',
            unit_price_ht REAL DEFAULT 0,
            vat_rate INTEGER DEFAULT 20,
            discount_percent REAL DEFAULT 0,
            item_type TEXT DEFAULT 'service',
            FOREIGN KEY (quote_id) REFERENCES quotes(id) ON DELETE CASCADE
        );
