CREATE TABLE quotes (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  client_id INTEGER,
  title TEXT,
  amount REAL DEFAULT 0,
  status TEXT DEFAULT 'draft',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, deal_id INTEGER, total_ht REAL DEFAULT 0, total_tva REAL DEFAULT 0, total_ttc REAL DEFAULT 0, deposit_rate INTEGER DEFAULT 0, deposit_amount REAL DEFAULT 0, validity_days INTEGER DEFAULT 30, valid_until TEXT, notes TEXT, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, number TEXT,
  FOREIGN KEY (client_id) REFERENCES clients(id)
);
